{
  "version": 1,
  "minor_version": 1,
  "key": "lovelace",
  "data": {
    "config": {
      "title": "Home of Banus",
      "views": [
        {
          "path": "default_view",
          "title": "Home",
          "icon": "mdi:home",
          "type": "sections",
          "max_columns": 3,
          "sections": [
            {
              "type": "grid",
              "column_span": 3,
              "cards": [
                {
                  "type": "custom:mushroom-chips-card",
                  "chips": [
                    {
                      "type": "template",
                      "icon": "mdi:lightbulb-group",
                      "icon_color": "{% if states.light | selectattr('state','eq','on') | list | count > 0 %}amber{% else %}disabled{% endif %}",
                      "content": "{{ states.light | selectattr('state','eq','on') | list | count }} / {{ states.light | list | count }} lights on",
                      "tap_action": {
                        "action": "none"
                      }
                    },
                    {
                      "type": "template",
                      "icon": "{% if is_state('cover.garage_door', 'open') or is_state('cover.garage_door', 'opening') %}mdi:garage-open{% else %}mdi:garage{% endif %}",
                      "icon_color": "{% if is_state('cover.garage_door', 'closed') %}green{% else %}orange{% endif %}",
                      "content": "Garage {{ states('cover.garage_door') | title }}",
                      "tap_action": {
                        "action": "more-info",
                        "entity": "cover.garage_door"
                      }
                    }
                  ]
                }
              ]
            },
            {
              "type": "grid",
              "column_span": 1,
              "cards": [
                {
                  "type": "custom:mushroom-cover-card",
                  "entity": "cover.garage_door",
                  "name": "Garage Door",
                  "icon": "mdi:garage",
                  "show_buttons_control": true,
                  "show_position_control": false,
                  "tap_action": {
                    "action": "more-info"
                  }
                }
              ]
            },
            {
              "type": "grid",
              "column_span": 2,
              "cards": [
                {
                  "type": "custom:hue-like-light-card",
                  "title": "Basement",
                  "lights": [
                    "light.dining",
                    "light.kitchen",
                    "light.living",
                    "light.entrance"
                  ]
                },
                {
                  "type": "custom:hue-like-light-card",
                  "title": "Bedroom",
                  "lights": [
                    "light.bedroom",
                    "light.wake_up_light"
                  ]
                },
                {
                  "type": "custom:hue-like-light-card",
                  "title": "Individual Lights",
                  "lights": [
                    "light.signe_gradient_floor_1",
                    "light.hue_filament_bulb_1",
                    "light.hue_filament_bulb_2",
                    "light.hue_pillar_spot_2",
                    "light.hue_pillar_spot_2_2",
                    "light.hue_pillar_spot_3",
                    "light.hue_pillar_spot_4",
                    "light.hue_pillar_spot_5"
                  ]
                }
              ]
            }
          ]
        },
        {
          "type": "sections",
          "max_columns": 4,
          "title": "Network",
          "path": "network",
          "icon": "mdi:console-network",
          "sections": [
            {
              "type": "grid",
              "cards": [
                {
                  "type": "entities",
                  "title": "AdGuard Home",
                  "entities": [
                    {
                      "entity": "switch.adguard_home_filtering",
                      "name": "Filtering"
                    },
                    {
                      "entity": "switch.adguard_home_parental_control",
                      "name": "Parental control"
                    },
                    {
                      "entity": "switch.adguard_home_protection",
                      "name": "Protection"
                    },
                    {
                      "entity": "switch.adguard_home_query_log",
                      "name": "Query log"
                    },
                    {
                      "entity": "switch.adguard_home_safe_browsing",
                      "name": "Safe browsing"
                    },
                    {
                      "entity": "switch.adguard_home_safe_search",
                      "name": "Safe search"
                    }
                  ]
                }
              ]
            }
          ],
          "cards": []
        }
      ]
    }
  }
}

