python3 << 'EOF'
import json

with open('/tmp/lovelace_config.json') as f:
    config = json.load(f)

home = config['views'][0]
sections = home['sections']

def hstack_has(s, entity):
    for c in s.get('cards', []):
        if c.get('type') == 'horizontal-stack':
            if any(x.get('entity','') == entity for x in c.get('cards',[])):
                return True
    return False

def has_entity(s, e):
    return any(c.get('entity','') == e for c in s.get('cards',[]))

def has_chip_type(s, t):
    for c in s.get('cards', []):
        for chip in c.get('chips', []):
            if chip.get('type') == t:
                return True
    return False

chips_status = next(s for s in sections if has_chip_type(s, 'weather'))
weather_sec  = next(s for s in sections if has_entity(s, 'weather.forecast_home_of_banus'))
garage_sec   = next(s for s in sections if has_entity(s, 'cover.garage_door'))
lights_sec   = next(s for s in sections if hstack_has(s, 'light.basement_lights'))
persons_sec  = next(s for s in sections if hstack_has(s, 'person.martin_banus'))
nav_sec      = next(s for s in sections if s is not chips_status and any('mushroom-chips-card' in c.get('type','') for c in s.get('cards',[])))

home['sections'] = [chips_status, weather_sec, garage_sec, lights_sec, persons_sec, nav_sec]

for i, s in enumerate(home['sections']):
    print(i, 'col_span:', s.get('column_span','?'), [c.get('entity', c.get('type','?')) for c in s.get('cards',[])])

with open('/tmp/lovelace_config.json', 'w') as f:
    json.dump(config, f, indent=2)
